export type IGetAsyncFnType<T> = T extends (...args: never[]) => Promise<infer R> ? R : T;
export type IGetOptional<T, V = never> = {
    [K in keyof T as undefined extends T[K] ? K : never]-?: T[K] | V;
};
export type IGetRequire<T, V = never> = {
    [K in keyof T as undefined extends T[K] ? never : K]-?: T[K] | V;
};
export type IEntity<T> = {
    [K in keyof T]: any extends T[K] ? never : T[K];
};
export type IPropertyGetField<T> = {
    [K in keyof T as `get${Capitalize<string & keyof T>}`]: T[K];
};
export type IPropertySetField<T> = {
    [K in keyof T as `set${Capitalize<string & keyof T>}`]: T[K];
};
export type kebabcase<S> = S extends `${infer first}${infer suf}` ? first extends Lowercase<first> ? `${first}${kebabcase<suf>}` : `-${Lowercase<first>}${kebabcase<suf>}` : S;
export type Reverse<T, R extends any[]> = T extends any[] ? T['length'] extends R['length'] ? R : Reverse<T, [T[R['length']], ...R]> : [];
export type Reverse1<T extends any[]> = T extends [infer First, ...infer Rest] ? [...Reverse1<Rest>, First] : [];
export type LengthOfString<S, T extends any[] = []> = S extends any[] ? S['length'] : S extends `${infer first}${infer rest}` ? LengthOfString<rest, [...T, first]> : T['length'];
export type Permutation<T, U = T> = T extends any ? [T, ...Permutation<Exclude<U, T>>] : [];
export type ArrToUnion<T extends any[], M = never> = T extends [
    infer U,
    ...infer Rest
] ? ArrToUnion<Rest, M | U> : M;
export type TupleToUnion<T extends any[]> = T[number];
